class Solution:
    def minimumEffort(self, tasks):
        order = sorted(tasks, key=lambda t: t[1] - t[0], reverse=True)

        def feasible(start):
            energy = start
            for actual, minimum in order:
                if energy < minimum:
                    return False
                energy -= actual
            return True

        lo, hi = 0, sum(t[1] for t in tasks)
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

