class Solution:
    def minimumEffort(self, tasks) -> int:
        order = sorted(tasks, key=lambda t: t[1] - t[0], reverse=True)
        energy = 0
        needed = 0
        for actual, minimum in order:
            if energy < minimum:
                needed += minimum - energy
                energy = minimum
            energy -= actual
        return needed

