var minimumEffort = function(tasks) {
    const order = [...tasks].sort((a, b) => (b[1] - b[0]) - (a[1] - a[0]));
    let energy = 0;
    let needed = 0;
    for (const [actual, minimum] of order) {
        if (energy < minimum) {
            needed += minimum - energy;
            energy = minimum;
        }
        energy -= actual;
    }
    return needed;
};
